// HP WW Capability Matrix — CINC Data
// Source: CINC_File_WW_Capability_Matrix_linkage.xlsx
// All lead times in WORKING DAYS. Reviewed quarterly by HP Supply Chain.
// OTD = Order to Delivery (HP order received → customer delivery)
// OTS = Order to Ship (HP order received → shipment from factory or DC)
// Note: supplies/poly OTS factory value is <1% — null stored here, treat as negligible

export type RTM = 'Direct' | 'Indirect' | 'DMFI' | 'Indent'
export type HPRegion = 'AMS' | 'EMEA' | 'APJ'

export interface CINCProductLeadTimes {
  notebooks:              number | null
  desktops:               number | null
  desktops_minis:         number | null
  printers:               number | null
  workstations:           number | null
  monitors:               number | null
  supplies:               number | null
  commercial_peripherals: number | null
  poly:                   number | null
  retail_solution:        number | null
}

export interface CINCEntry extends CINCProductLeadTimes {
  country:    string     // e.g. 'United Kingdom'
  iso:        string     // ISO 3166-1 alpha-2 e.g. 'GB'
  region:     HPRegion   // AMS | EMEA | APJ
  market:     string     // HP market grouping
  rtm:        RTM        // Route to Market
  hp_dest:    string     // Country where HP can physically deliver to
  final_dest: string     // Customer final destination
  notes:      string     // Supply chain notes
}

export interface OTSEntry extends CINCProductLeadTimes {
  label: string
}

export interface CINCAssumption {
  category: string
  text:     string
}

