// ─── Helper Functions ────────────────────────────────────────────────────────

/** Look up all CINC entries for a country (by ISO alpha-2 or name) */
export function getCINCByCountry(isoOrName: string): CINCEntry[] {
  const q = isoOrName.trim().toUpperCase()
  return CINC_OTD.filter(e =>
    e.iso.toUpperCase() === q ||
    e.country.toUpperCase() === isoOrName.trim().toUpperCase()
  )
}

/** Get preferred RTM entry (Direct > DMFI > Indirect > Indent) */
export function getPreferredCINC(isoOrName: string): CINCEntry | null {
  const entries = getCINCByCountry(isoOrName)
  if (!entries.length) return null
  const priority: RTM[] = ['Direct', 'DMFI', 'Indirect', 'Indent']
  for (const rtm of priority) {
    const found = entries.find(e => e.rtm === rtm)
    if (found) return found
  }
  return entries[0]
}

/** Flag entries with long printer lead times (default >30 working days) */
export function getLongLeadTimeCountries(thresholdDays = 30): CINCEntry[] {
  return CINC_OTD.filter(e => e.printers !== null && e.printers > thresholdDays)
}

/** Countries where HP destination differs from final destination */
export function getIndirectDeliveryCountries(): CINCEntry[] {
  return CINC_OTD.filter(e =>
    e.hp_dest.trim().toLowerCase() !== e.final_dest.trim().toLowerCase() &&
    e.hp_dest.trim().toLowerCase() !== e.country.trim().toLowerCase()
  )
}

/** All available RTMs for a country */
export function getAvailableRTMs(isoOrName: string): RTM[] {
  return [...new Set(getCINCByCountry(isoOrName).map(e => e.rtm))] as RTM[]
}

/** Worst-case OTD across multiple countries (for multi-country deals) */
export function getMultiCountryLeadTimes(isos: string[]): Partial<CINCProductLeadTimes> {
  const result: Partial<CINCProductLeadTimes> = {}
  const keys: (keyof CINCProductLeadTimes)[] = [
    'notebooks','desktops','desktops_minis','printers','workstations',
    'monitors','supplies','commercial_peripherals','poly','retail_solution'
  ]
  for (const iso of isos) {
    const entry = getPreferredCINC(iso)
    if (!entry) continue
    for (const key of keys) {
      const val = entry[key]
      if (val !== null) {
        result[key] = Math.max((result[key] as number) ?? 0, val)
      }
    }
  }
  return result
}

/** Risk flag: returns severity based on printer lead time */
export function getDeliveryRiskLevel(printerDays: number | null): 'critical' | 'high' | 'medium' | 'low' | 'unknown' {
  if (printerDays === null) return 'unknown'
  if (printerDays > 90) return 'critical'
  if (printerDays > 60) return 'high'
  if (printerDays > 30) return 'medium'
  return 'low'
}
